const rows = $input.all().map(i => i.json);
if (rows.length === 0) return [{ json: { no_referrals: true } }];

// Determine credit amount based on referrer's plan tier
const tierCredits = {
  core: { dimension: 'ai_generations', quantity: 50, label: 'Bronze (10%)' },
  growth: { dimension: 'ai_generations', quantity: 100, label: 'Silver (15%)' },
  scale: { dimension: 'ai_generations', quantity: 150, label: 'Gold (15% + extras)' },
};

const rewards = rows.map(row => {
  const tier = row.plan_slug || 'core';
  const credit = tierCredits[tier] || tierCredits.core;
  return {
    json: {
      referral_id: row.referral_id,
      referrer_organization_id: row.referrer_organization_id,
      referrer_name: row.referrer_name,
      dimension: credit.dimension,
      quantity: credit.quantity,
      tier_label: credit.label,
    }
  };
});

return rewards;
